challenge.solution:
interface UserCardProps {
  name: string;
  email: string;
  role: 'admin' | 'user' | 'guest';
  onPromote?: (name: string) => void;
}

export default function UserCard({ name, email, role, onPromote }: UserCardProps) {
  return (
    <div style={{ border: '1px solid #ccc', padding: 16, borderRadius: 8 }}>
      <h2>{name}</h2>
      <p>{email}</p>
      <span>{role}</span>
      {onPromote && (
        <button onClick={() => onPromote(name)}>Promover</button>
      )}
    </div>
  );
}
